queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?restaurant a :Restaurant .
    ?restaurant p:name ?name .
    ?restaurant p:openingHours ?openinghours_f .
    FILTER(STR(?openinghours_f) = "9 AM to 11 PM")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?bar a :Bar .
    ?bar p:name ?name .
    ?bar p:openingHours ?openinghours_f .
    FILTER(STR(?openinghours_f) = "9 AM to 11 PM")
    BIND(?name AS ?o0)
  }
}

